var m_chart_chartjs_helpers={locale:"en-US"};(function($){"use strict";m_chart_chartjs_helpers.init=function(){$(".m-chart").on("render_start",function(event){var chart_object="m_chart_chartjs_"+event.post_id+"_"+event.instance;if("undefined"===typeof window[chart_object]){return}m_chart_chartjs_helpers.locale=window[chart_object].chart_args.options.locale;var type=window[chart_object].chart_args.type;var labels_pos=window[chart_object].chart_args.labels_pos;if("bubble"==window[chart_object].chart_args.type){window[chart_object].chart_args.data=m_chart_chartjs_helpers.preprocess_bubble_data(window[chart_object].chart_args.data);window[chart_object].chart_args.options.plugins.tooltip.callbacks={label:item=>{return m_chart_chartjs_helpers.bubble_chart_tooltip_label(item)}}}else if("scatter"==window[chart_object].chart_args.type){window[chart_object].chart_args.options.plugins.tooltip.callbacks={label:item=>{return m_chart_chartjs_helpers.scatter_chart_tooltip_label(item)}}}else{window[chart_object].chart_args.options.plugins.tooltip.callbacks={label:item=>{return m_chart_chartjs_helpers.chart_tooltip_label(item,type,labels_pos)}}}window[chart_object].chart_args.options.plugins.datalabels.formatter=function(label){if(null===label){return label}if("undefined"!==typeof label.label){label=label.label}else if("undefined"!==typeof label.r){label=label.r}else if("undefined"!==typeof label.y){label=label.y}if($.isNumeric(label)){return m_chart_chartjs_helpers.number_format(label)}else{return label}}})};m_chart_chartjs_helpers.preprocess_bubble_data=function($data){const value_range=$data.datasets[0].data.reduce((acc,val)=>Math.max(acc,val.r),0);const pixel_max=31;const pixel_min=1;const pixel_range=pixel_max-pixel_min;for(const ds of $data.datasets){for(const d of ds.data){d.original=d.r;const percentage_radius=Math.sqrt(Math.abs(d.r)/value_range);d.r=percentage_radius*pixel_range+pixel_min}}return $data};m_chart_chartjs_helpers.bubble_chart_tooltip_label=function(item){var tooltip_label=[item.raw.label,item.chart.data.labels[0]+": "+m_chart_chartjs_helpers.number_format(item.parsed.x),item.chart.data.labels[1]+": "+m_chart_chartjs_helpers.number_format(item.parsed.y),item.chart.data.labels[2]+": "+m_chart_chartjs_helpers.number_format(item.raw.original)];return tooltip_label};m_chart_chartjs_helpers.scatter_chart_tooltip_label=function(item){var tooltip_label=[item.dataset.label,item.chart.data.labels[0]+": "+m_chart_chartjs_helpers.number_format(item.parsed.x),item.chart.data.labels[1]+": "+m_chart_chartjs_helpers.number_format(item.parsed.y)];return tooltip_label};m_chart_chartjs_helpers.chart_tooltip_label=function(item,type,labels_pos){var label=item.dataset.label;if(null==item.raw){return null}if("undefined"==typeof label){label=item.label}if("bar"==type){label=""}if("polarArea"==type){label=item.chart.data.labels[item.dataIndex]}if("both"!=labels_pos){label=""}if("undefined"!=typeof item.dataset.label&&label!=item.dataset.label){label+=item.dataset.label}if(""!=label){label+=": "}var raw=item.dataset.rawData&&item.dataset.rawData[item.dataIndex];var raw_value;if(raw&&null!==raw.value){raw_value=(raw.prefix||"")+m_chart_chartjs_helpers.number_format(raw.value)+(raw.suffix||"")}else if(raw&&raw.text){raw_value=raw.text}else{raw_value=m_chart_chartjs_helpers.number_format(item.raw)}return label+raw_value};m_chart_chartjs_helpers.number_format=function(number){return Chart.helpers.formatNumber(number,m_chart_chartjs_helpers.locale)};$(function(){m_chart_chartjs_helpers.init()})})(jQuery);